package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair3911DifferenceFindingTest {

    private final ClonePair3911 subject = new ClonePair3911();

    /**
     * Generated by Codex (GPT-5.4).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        InvocationOutcome method1Outcome = capture(values -> subject.method1((double[]) values[0], (double[]) values[1]), new Object[]{new double[]{1.0, 2.0}, new double[]{-1.0, 0.0, 1.0}});
        InvocationOutcome method2Outcome = capture(values -> subject.method2((double[]) values[0], (double[]) values[1]), new Object[]{new double[]{1.0, 2.0}, new double[]{-1.0, 0.0, 1.0}});

        assertOutcome(
            method1Outcome,
            "OK",
            "Double(2.0)",
            null,
            "",
            "",
            "java.lang.Object[][double[][1.0, 2.0],double[][-1.0, 0.0, 1.0]]",
            "java.lang.Object[][double[][1.0, 2.0],double[][-1.0, 0.0, 1.0]]"
        );
        assertOutcome(
            method2Outcome,
            "OK",
            "Double(2.8284271247461903)",
            null,
            "",
            "",
            "java.lang.Object[][double[][1.0, 2.0],double[][-1.0, 0.0, 1.0]]",
            "java.lang.Object[][double[][1.0, 2.0],double[][-1.0, 0.0, 1.0]]"
        );
    }
}
